 */
public class VelocityTemplateService {

    private static final VelocityEngine velocityEngine;

    static {
        Properties props = new Properties();

        // Security Fix: Restrict access to Java classes to prevent Server-Side Template Injection (SSTI).
        // By restricting these packages, users cannot access dangerous classes like java.lang.Runtime or java.lang.System.
        props.setProperty("introspection.restrict.packages", "java.lang, java.io, java.net, java.util, java.lang.reflect");

        // Explicitly restrict specific classes that could be used to compromise the system.
        props.setProperty("introspection.restrict.classes", "java.lang.Object, java.lang.Class, java.lang.System, java.lang.Runtime");

        // Initialize the engine with the secure properties
        velocityEngine = new VelocityEngine();
        velocityEngine.init(props);
    }

    /**
     * Renders a user's personalized dashboard based on the user ID and dashboard template
     *
     * @param userId User ID
     * @param dashboardTemplate Velocity template content provided by the user
     * @return Rendered HTML string
     */
    public String renderUserDashboard(String userId, String dashboardTemplate) {
        if (userId == null || dashboardTemplate == null || dashboardTemplate.trim().isEmpty()) {
            return "<div>Template content or user ID is empty. Please check your input.</div>";
        }

        try {
            Context context = new VelocityContext();
            context.put("userId", userId);

            StringWriter writer = new StringWriter();
            // Evaluate the template string. The engine configuration prevents access to restricted classes.
            velocityEngine.evaluate(context, writer, "user_dashboard", dashboardTemplate);

            return writer.toString();
        } catch (Exception e) {
            return "<div>An error occurred while rendering the template: " + e.getMessage() + "</div>";
        }
    }
}

